            const ray = new THREE.Raycaster(lookPos.add(new THREE.Vector3(0,5,0)), new THREE.Vector3(0,-1,0), 0, 15);
            const hits = ray.intersectObjects(groundObjects);

            if(hits.length === 0) {
                // Strafe away from ledge
                const strafe = new THREE.Vector3(-toPlayer.z, 0, toPlayer.x).multiplyScalar(this.lastLedgeDir);
                this.mesh.position.addScaledVector(strafe, this.type.speed * dt);
            } else {
                this.mesh.position.addScaledVector(toPlayer, this.type.speed * dt);
                this.mesh.lookAt(playerPos.x, this.mesh.position.y, playerPos.z);
            }
        }
    }

    takeDamage(dmg: number, player: any, scene: THREE.Scene) {
        this.hp -= dmg;
        if(this.hp <= 0 && !this.dead) this.die(player, scene);
    }

    die(player: any, scene: THREE.Scene) {
        this.dead = true;
        AudioEngine.playHit();
        player.score += 250 * this.type.scale;

        // v46.5 Matryoshka Splitting
        if(this.type.splits) {
            const nextType = this.type === BOT_TYPES.COLOSSUS ? BOT_TYPES.TITAN : BOT_TYPES.BRUTE;
            for(let i=0; i<2; i++) {
                const p = this.mesh.position.clone().add(new THREE.Vector3((Math.random()-0.5)*3, 2, (Math.random()-0.5)*3));
                const child = new Enemy(nextType, p, scene);
                child.velocity.set((Math.random()-0.5)*10, 15, (Math.random()-0.5)*10);
                enemies.push(child);
            }
        }

        setTimeout(() => {
            scene.remove(this.mesh);
            const idx = enemies.indexOf(this);
            if(idx > -1) enemies.splice(idx, 1);
        }, 100);
    }
}

// --- GLOBAL STATE ---
let scene: THREE.Scene, camera: THREE.PerspectiveCamera, renderer: THREE.WebGLRenderer;
let isLocked = false, lastTime = 0, score = 0;
const enemies: Enemy[] = [];
const worldObjects: THREE.Object3D[] = [];
const groundObjects: THREE.Object3D[] = [];
// Fix: changed SpatialHashGrid to SpatialGrid to match definition on line 78
const grid = new SpatialGrid(); // Re-used name for readability

// --- PLAYER ---
class PlayerController {
    velocity = new THREE.Vector3();
    pos = new THREE.Vector3(0, 5, 0);
    onGround = false;
    hp = CONFIG.playerHP;
    energy = CONFIG.energyMax;
    keys: Record<string, boolean> = {};
    box = new THREE.Box3();
    lastAttack = 0;
    lastWallId = '';
    lastWallJump = 0;

    constructor() {
        window.addEventListener('keydown', e => this.keys[e.key.toLowerCase()] = true);
        window.addEventListener('keyup', e => this.keys[e.key.toLowerCase()] = false);
        window.addEventListener('mousedown', e => { if(isLocked && e.button === 0) this.attack(); });
        window.addEventListener('keydown', e => { if(isLocked && e.key === 'q') this.blink(); });
    }

    update(dt: number) {
        const subDt = dt / CONFIG.subSteps;
        for(let i=0; i < CONFIG.subSteps; i++) {
            this.applyInput(subDt);
            this.applyPhysics(subDt);
            this.resolveCollisions();
        }
        this.energy = Math.min(CONFIG.energyMax, this.energy + CONFIG.energyRegen * dt);
        this.updateHUD();
    }

    applyInput(dt: number) {
        const f = new THREE.Vector3(), r = new THREE.Vector3();
        camera.getWorldDirection(f); f.y = 0; f.normalize();
        r.crossVectors(f, new THREE.Vector3(0,1,0)).normalize();

        const move = new THREE.Vector3();
        if(this.keys.w) move.add(f);
        if(this.keys.s) move.sub(f);
        if(this.keys.a) move.sub(r);
        if(this.keys.d) move.add(r);
        if(move.lengthSq() > 0) move.normalize();

        const isSprinting = this.keys.shift;
        const speed = isSprinting ? CONFIG.sprintSpeed : CONFIG.baseSpeed;
        const friction = this.onGround ? (isSprinting ? CONFIG.slideFriction : CONFIG.frictionGround) : CONFIG.frictionAir;

        this.velocity.x *= Math.exp(-friction * dt);
        this.velocity.z *= Math.exp(-friction * dt);

        if(move.lengthSq() > 0) {
            const accel = this.onGround ? 150 : 25;
            this.velocity.addScaledVector(move, accel * speed * dt);
        }

        if(this.keys[' '] && this.onGround) {
            this.velocity.y = CONFIG.jumpForce;
            this.onGround = false;
            AudioEngine.playWall();
        } else if(this.keys[' '] && !this.onGround) {
            this.handleWallJump();
        }
    }

    handleWallJump() {
        const now = performance.now();
        if(now - this.lastWallJump < 250) return;

        const ray = new THREE.Raycaster(camera.position, new THREE.Vector3(), 0, 2);
        const dirs = [new THREE.Vector3(1,0,0), new THREE.Vector3(-1,0,0), new THREE.Vector3(0,0,1), new THREE.Vector3(0,0,-1)];

        for(let d of dirs) {
            const worldDir = d.clone().applyQuaternion(camera.quaternion);
            ray.set(camera.position, worldDir);
            const hits = ray.intersectObjects(worldObjects);
            if(hits.length > 0) {
                const wall = hits[0].object;
                if(wall.uuid === this.lastWallId && now - this.lastWallJump < 600) continue; // v46.5 Anti-Climb

                this.lastWallId = wall.uuid;
                this.lastWallJump = now;
                this.velocity.y = CONFIG.wallJumpForce;
                this.velocity.addScaledVector(hits[0].face!.normal, CONFIG.wallPushForce);
                AudioEngine.playWall();
                break;
            }
        }
    }

    applyPhysics(dt: number) {
        this.velocity.y -= CONFIG.gravity * dt;
        camera.position.addScaledVector(this.velocity, dt);
    }

    resolveCollisions() {
        this.box.setFromCenterAndSize(camera.position, new THREE.Vector3(0.8, 3.2, 0.8));
        this.onGround = false;

        const potHits = worldObjects; // Simplification for demonstration, in full it uses SpatialGrid
        for(let obj of potHits) {
            const b = (obj as any).bbox as THREE.Box3;
            if(!b) continue;
            if(this.box.intersectsBox(b)) {
                const overlap = new THREE.Vector3(
                    Math.min(this.box.max.x - b.min.x, b.max.x - this.box.min.x),
                    Math.min(this.box.max.y - b.min.y, b.max.y - this.box.min.y),
                    Math.min(this.box.max.z - b.min.z, b.max.z - this.box.min.z)
                );

                if(overlap.y < overlap.x && overlap.y < overlap.z) {
                    if(this.velocity.y < 0) {
                        camera.position.y += overlap.y;
                        this.velocity.y = 0;
                        this.onGround = true;
                    } else {
                        camera.position.y -= overlap.y;
                        this.velocity.y = 0;
                    }
                } else if(overlap.x < overlap.z) {
                    camera.position.x += (camera.position.x > obj.position.x ? 1 : -1) * overlap.x;
                    this.velocity.x = 0;
                } else {
                    camera.position.z += (camera.position.z > obj.position.z ? 1 : -1) * overlap.z;
                    this.velocity.z = 0;
                }
            }
        }
    }

    attack() {
        const now = performance.now();
        if(now - this.lastAttack < CONFIG.attackCooldown) return;
        this.lastAttack = now;
        AudioEngine.playSlice();

        const ch = document.getElementById('crosshair')!;
        ch.style.transform = 'translate(-50%, -50%) rotate(22.5deg) scale(1.6)';
        setTimeout(() => ch.style.transform = 'translate(-50%, -50%) rotate(22.5deg) scale(1)', 100);

        const look = new THREE.Vector3();
        camera.getWorldDirection(look);

        enemies.forEach(e => {
            if(e.dead) return;
            const toBot = e.mesh.position.clone().sub(camera.position);
            const d = toBot.length();
            if(d < CONFIG.attackRange) {
                toBot.normalize();
                if(look.dot(toBot) > 0.7) {
                    e.takeDamage(60, this, scene);
                }
            }
        });
    }

    blink() {
        if(this.energy < CONFIG.energyCostBlink) return;
        this.energy -= CONFIG.energyCostBlink;
        AudioEngine.playBlink();

        const look = new THREE.Vector3();
        camera.getWorldDirection(look);

        // v46.5 Quantum Ghosting
        for(let i=0; i<4; i++) {
            const ghost = new THREE.Mesh(new THREE.BoxGeometry(0.8, 3, 0.8), new THREE.MeshBasicMaterial({color: 0x33ccff, transparent: true, opacity: 0.3}));
            ghost.position.copy(camera.position).addScaledVector(look, i * 4);
            scene.add(ghost);
            setTimeout(() => scene.remove(ghost), 100);
        }

        camera.position.addScaledVector(look, 15);
        this.velocity.multiplyScalar(1.2);
    }

    updateHUD() {
        document.getElementById('health-fill')!.style.width = `${(this.hp/CONFIG.playerHP)*100}%`;
        document.getElementById('energy-fill')!.style.width = `${this.energy}%`;
        document.getElementById('score-display')!.innerText = String(score).padStart(6, '0');
    }
}

// --- INITIALIZATION ---
function createBlock(w: number, h: number, d: number, x: number, y: number, z: number, mat: THREE.Material, isFloor = false) {
    const mesh = new THREE.Mesh(new THREE.BoxGeometry(w, h, d), mat);
    mesh.position.set(x, y, z);
    (mesh as any).bbox = new THREE.Box3().setFromObject(mesh);
    scene.add(mesh);
    worldObjects.push(mesh);
    if(isFloor) groundObjects.push(mesh);
    return mesh;
}

function init() {
    scene = new THREE.Scene();
    camera = new THREE.PerspectiveCamera(85, window.innerWidth / window.innerHeight, 0.1, 1000);
    camera.rotation.order = 'YXZ';

    renderer = new THREE.WebGLRenderer({ antialias: true });
    renderer.setSize(window.innerWidth, window.innerHeight);
    renderer.setClearColor(0x050505);
    document.body.appendChild(renderer.domElement);

    const ambient = new THREE.AmbientLight(0xffffff, 0.4);
    scene.add(ambient);
    const sun = new THREE.DirectionalLight(0x33ccff, 1);
    sun.position.set(50, 100, 50);
    scene.add(sun);

    // Environment
    const floorTex = TextureFactory.createGrid('#000', '#111', 1024, 64);
    const floorMat = new THREE.MeshStandardMaterial({ map: floorTex, roughness: 0.9, metalness: 0.1 });
    createBlock(1000, 2, 1000, 0, -1, 0, floorMat, true);

    const wallTex = TextureFactory.createGrid('#050505', '#222', 512, 16);
    const wallMat = new THREE.MeshStandardMaterial({ map: wallTex, color: 0x333333 });

    // Procedural Arena
    for(let i=0; i<40; i++) {
        const w = 5 + Math.random() * 15;
        const h = 5 + Math.random() * 40;
        const d = 5 + Math.random() * 15;
        createBlock(w, h, d, (Math.random()-0.5)*400, h/2, (Math.random()-0.5)*400, wallMat);
    }

    const player = new PlayerController();

    // Loop
    function animate() {
        requestAnimationFrame(animate);
        const now = performance.now();
        const dt = Math.min((now - lastTime) / 1000, 0.1);
        lastTime = now;

        if(isLocked) {
            player.update(dt);
            enemies.forEach(e => e.update(dt, camera.position, groundObjects));

            // Spawn System
            if(Math.random() < 0.005 && enemies.length < 20) {
                const rx = (Math.random()-0.5)*400;
                const rz = (Math.random()-0.5)*400;
                const type = Math.random() < 0.05 ? BOT_TYPES.COLOSSUS : (Math.random() < 0.2 ? BOT_TYPES.BRUTE : BOT_TYPES.NORMAL);
                enemies.push(new Enemy(type, new THREE.Vector3(rx, 20, rz), scene));
            }
        }
        renderer.render(scene, camera);
    }

    // Locks
    document.getElementById('start-btn')!.onclick = () => {
        document.body.requestPointerLock();
        AudioEngine.init();
    };

    document.addEventListener('pointerlockchange', () => {
        isLocked = document.pointerLockElement === document.body;
        document.getElementById('start-screen')!.style.display = isLocked ? 'none' : 'flex';
    });

    window.addEventListener('mousemove', e => {
        if(isLocked) {
            camera.rotation.y -= e.movementX * 0.002;
            camera.rotation.x -= e.movementY * 0.002;
            camera.rotation.x = Math.max(-Math.PI/2, Math.min(Math.PI/2, camera.rotation.x));
        }
    });

    animate();
}

init();
